mapper.select:
SELECT COUNT(1)
FROM sys_user
WHERE deleted_flag = 0
  AND last_login_time IS NOT NULL

    AND last_login_time >= #{startTime}


    AND last_login_time < #{endTime}

SELECT COUNT(1)
FROM chat_message cm
INNER JOIN chat_conversation cc ON cc.id = cm.conversation_id
WHERE cc.scene_type IN ('hall_channel', 'global_channel')

    AND cm.created_at >= #{startTime}


    AND cm.created_at < #{endTime}

SELECT COUNT(1)
FROM sys_report_record
WHERE 1 = 1

    AND status = #{status}


    AND reported_at >= #{startTime}


    AND reported_at < #{endTime}

SELECT fs.id AS sectionId, fs.name AS sectionName, COALESCE(fp.post_count, 0) AS postCount, COALESCE(fr.reply_count, 0) AS replyCount, COALESCE(fp.post_count, 0) + COALESCE(fr.reply_count, 0) AS hotValue FROM forum_section fs LEFT JOIN ( SELECT section_id, COUNT(1) AS post_count FROM forum_post WHERE status != 4
GROUP BY section_id ) fp ON fp.section_id = fs.id LEFT JOIN ( SELECT fp_inner.section_id, COUNT(fr_inner.id) AS reply_count FROM forum_reply fr_inner INNER JOIN forum_post fp_inner ON fp_inner.id = fr_inner.post_id WHERE fr_inner.status != 3
AND fr_inner.created_at >= #{startTime}
AND fr_inner.created_at < #{endTime}
GROUP BY fp_inner.section_id ) fr ON fr.section_id = fs.id WHERE COALESCE(fp.post_count, 0) + COALESCE(fr.reply_count, 0) > 0 ORDER BY hotValue DESC, postCount DESC, fs.id ASC LIMIT #{limit}

SELECT ROUND(AVG(TIMESTAMPDIFF(SECOND, reported_at, handled_at)) / 60, 2)
FROM sys_report_record
WHERE handled_at IS NOT NULL

    AND handled_at >= #{startTime}


    AND handled_at < #{endTime}

SELECT COALESCE(NULLIF(TRIM(punishment_type), ''), 'none') AS punishmentType, COUNT(1) AS count FROM sys_report_record WHERE handled_at IS NOT NULL
AND handled_at >= #{startTime}
AND handled_at < #{endTime}
GROUP BY COALESCE(NULLIF(TRIM(punishment_type), ''), 'none') ORDER BY count DESC, punishmentType ASC
